#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$validationMsgSNP} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$validationMsgGeno} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$validationMsg} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$covDescGroup$covDescTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$snpSummaryTablesGroup$snpSummaryTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$snpResults} \tab \tab \tab \tab \tab Results for each SNP \cr
#'   \code{results$ldGroup$ldTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$ldGroup$ldMatrixTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$ldGroup$ldPlotImage} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$haploGroup$haploFreqTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$haploGroup$haploAssocTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$haploGroup$haploInteractionTable} \tab \tab \tab \tab \tab a table \cr
#' }
#'
#' @export
snpAnalysis <- function(
    data,
    response,
    snps,
    covariates = NULL,
    responseType = "auto",
    subpop = FALSE,
    covDesc = FALSE,
    snpSummary = FALSE,
    allFreq = FALSE,
    genoFreq = FALSE,
    hweTest = FALSE,
    ldAnalysis = FALSE,
    ldMatrix = FALSE,
    ldMetric = "r2",
    ldPlot = FALSE,
    snpAssoc = FALSE,
    modelCodominant = FALSE,
    modelDominant = FALSE,
    modelRecessive = FALSE,
    modelOverdominant = FALSE,
    modelLogAdditive = FALSE,
    ciWidth = 95,
    snpInteraction = FALSE,
    haploFreq = FALSE,
    haploFreqMin = 0.01,
    haploAssoc = FALSE,
    haploInteraction = FALSE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("snpAnalysis requires jmvcore to be installed (restart may be required)")

    if ( ! missing(response)) response <- jmvcore::resolveQuo(jmvcore::enquo(response))
    if ( ! missing(snps)) snps <- jmvcore::resolveQuo(jmvcore::enquo(snps))
    if ( ! missing(covariates)) covariates <- jmvcore::resolveQuo(jmvcore::enquo(covariates))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(response), response, NULL),
            `if`( ! missing(snps), snps, NULL),
            `if`( ! missing(covariates), covariates, NULL))


    options <- snpAnalysisOptions$new(
        response = response,
        snps = snps,
        covariates = covariates,
        responseType = responseType,
        subpop = subpop,
        covDesc = covDesc,
        snpSummary = snpSummary,
        allFreq = allFreq,
        genoFreq = genoFreq,
        hweTest = hweTest,
        ldAnalysis = ldAnalysis,
        ldMatrix = ldMatrix,
        ldMetric = ldMetric,
        ldPlot = ldPlot,
        snpAssoc = snpAssoc,
        modelCodominant = modelCodominant,
        modelDominant = modelDominant,
        modelRecessive = modelRecessive,
        modelOverdominant = modelOverdominant,
        modelLogAdditive = modelLogAdditive,
        ciWidth = ciWidth,
        snpInteraction = snpInteraction,
        haploFreq = haploFreq,
        haploFreqMin = haploFreqMin,
        haploAssoc = haploAssoc,
        haploInteraction = haploInteraction)

    analysis <- snpAnalysisClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

